AreaManager = class("AreaManager", EventObservable)

function AreaManager:ctor()
end

function AreaManager:init()
    --是否允许锻炼
    self:registerEvent(S2CLSIsAllowWorkout, function(data)
        self:onIsAllowWorkoutChange(data)
    end)

    --是否允许攻击
    self:registerEvent(S2CLSIsAllowAttack, function(data)
        self:onIsAllowAttackChange(data)
    end)

    --玩家进入或离开某个区域
    self:registerEvent(S2CLSStayAreaInfo, function(data)
        self:onStayAreaInfoChange(data)
    end)

    self:registerEvent(S2CLSAutoAreaInfo, function(data)
        self:onAutoAreaInfo(data)
    end)
end

function AreaManager:onIsAllowWorkoutChange(data)
    if not GUIMainControl:isLoad() then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    self:enableWorkout(builder:getBoolParam("isAllowWorkout"))
end

function AreaManager:onIsAllowAttackChange(data)
    if not GUIMainControl:isLoad() then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    self:enableAttack(builder:getBoolParam("isAllowAttack"))
end

function AreaManager:onStayAreaInfoChange(data)
    if not GUIMainControl:isLoad() then
        return
    end

    local builder = DataBuilder.new():fromData(data)
    local areaType = builder:getNumberParam("areaType")
    local isEnter = builder:getBoolParam("isEnter")

    if isEnter == true and areaType == Define.Area.AutoArea then
        self:onEnterAutoArea()
    else
        self:onLeaveAutoArea()
    end
end

function AreaManager:onAutoAreaInfo(data)
    local builder = DataBuilder.new():fromData(data)
    local userId = builder:getParam("userId")
    local isEnter = builder:getBoolParam("isEnter")

    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end

    player:enterAutoArea(isEnter)
    --AutoAnimManager:playerEnterAutoArea(userId, isEnter)
end

function AreaManager:onEnterAutoArea()
    GUIMainControl:showGameTip("gui_enter_auto_area", 5000)
    GUIMainControl.ivEquipEffect:SetVisible(true)
    if GUIMainControl.selectMode ~= Define.SelectMode.Equip then
        GUIMainControl:onButtonSelect(Define.SelectMode.Equip, true)
    end
    GUIMainControl.autoWorkout = true

    --local player = PlayerManager:getClientPlayer()
    --if player then
    --    player:setUpperActionListenable(false)
    --end
end

function AreaManager:onLeaveAutoArea()
    GUIMainControl:hideGameTip()
    --GUIMainControl.ivEquipEffect:SetVisible(false)
    GUIMainControl.autoWorkout = false

    local player = PlayerManager:getClientPlayer()
    if player then
        player:setUpperActionListenable(true)
    end
end

function AreaManager:enableAttack(isAllow)
    PlayerManager:getClientPlayer().property.canAttack = isAllow
    --print("AreaManager:enableAttack " .. tostring(isAllow))
end

function AreaManager:enableWorkout(isAllow)
    PlayerManager:getClientPlayer().property.canWorkout = isAllow
    --print("AreaManager:enableWorkout " .. tostring(isAllow))
end

return AreaManager